    broadcastEvent("webhook_alert", {
        platform: platform,
        sender: sender,
        scan: scanEntry,
        stats: db.getStats()
    });

    res.json({
        status: "processed",
        verdict: analysis.verdict,
        score: analysis.risk_score,
        details: analysis.details
    });
});

